INSERT INTO public.articles (title, excerpt, content, author, date, category, image_url) VALUES
('أهمية العناية اليومية بالأسنان', 'تعرف على الطرق الصحيحة للعناية بأسنانك يومياً والحفاظ على صحة فمك', 'العناية اليومية بالأسنان هي الأساس للحفاظ على صحة الفم والأسنان. يجب تنظيف الأسنان مرتين يومياً على الأقل باستخدام معجون أسنان يحتوي على الفلورايد، واستخدام خيط الأسنان مرة واحدة يومياً لإزالة بقايا الطعام من بين الأسنان.', 'د. سارة أحمد', '2025-11-01', 'عناية يومية', 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=800&auto=format&fit=crop&q=60'),
('تقويم الأسنان: دليل شامل', 'كل ما تحتاج معرفته عن تقويم الأسنان وأنواعه المختلفة', 'تقويم الأسنان يساعد في تصحيح وضعية الأسنان والفكين. هناك أنواع متعددة مثل التقويم المعدني، والتقويم الشفاف (Invisalign)، والتقويم الخزفي. اختيار النوع المناسب يعتمد على حالة المريض وتوصية الطبيب.', 'د. محمد علي', '2025-10-28', 'تقويم', 'https://images.unsplash.com/photo-1588776814546-1ffcf47267a5?w=800&auto=format&fit=crop&q=60'),
('زراعة الأسنان: الحل الأمثل', 'كيف تعوض الأسنان المفقودة بأحدث التقنيات', 'تعتبر زراعة الأسنان الحل الأكثر استدامة لتعويض الأسنان المفقودة. تعتمد على غرس وتد من التيتانيوم في عظم الفك ليعمل كجذر صناعي، ثم يركب عليه التاج. نسبة نجاح الزراعة تتجاوز 95%.', 'د. فاطمة حسن', '2025-10-25', 'زراعة', 'https://images.unsplash.com/photo-1516062423079-7ca13cdc7f5a?w=800&auto=format&fit=crop&q=60'),
('تبييض الأسنان: حقائق وخرافات', 'ما هي الطرق الآمنة لتبييض الأسنان؟', 'تبيض الأسنان إجراء تجميلي شائع. يجب الحذر من الوصفات المنزلية غير الموثوقة التي قد تؤذي المينا. التبييض الاحترافي في العيادة هو الأكثر أماناً وفعالية.', 'د. خالد يوسف', '2025-10-22', 'تجميل', 'https://images.unsplash.com/photo-1593054918504-318a7764877e?w=800&auto=format&fit=crop&q=60'),
('أعراض التهاب اللثة', 'كيف تكتشف التهاب اللثة مبكراً؟', 'نزيف اللثة عند التنظيف، احمرار وتورم اللثة، ورائحة الفم الكريهة هي علامات مبكرة لالتهاب اللثة. إهمال العلاج قد يؤدي إلى انحسار اللثة وفقدان الأسنان.', 'د. ليلى عمر', '2025-10-18', 'تنظيف', 'https://images.unsplash.com/photo-1629909613654-28e377c37b09?w=800&auto=format&fit=crop&q=60'),
('العناية بأسنان الأطفال', 'متى تبدأ العناية بأسنان طفلك؟', 'يجب البدء بتنظيف لثة الطفل بقطعة شاش مبللة حتى قبل ظهور الأسنان. عند ظهور أول سن، يجب استخدام فرشاة أسنان ناعمة ومراجعة طبيب الأسنان.', 'د. أمل حسين', '2025-10-15', 'اطفال', 'https://images.unsplash.com/photo-1460380411175-d261998544d1?w=800&auto=format&fit=crop&q=60'),
('الفينير: ابتسامة هوليود', 'تحسين مظهر الأسنان بالقشور التجميلية', 'الفينير قشور رقيقة تصنع خصيصاً لتغطية السطح الأمامي للأسنان لتحسين اللون، الشكل، الحجم، أو الطول. تعتبر خياراً ممتازاً لتجميل الابتسامة بشكل دائم.', 'د. رامي صالح', '2025-10-12', 'حشوات تجميلية', 'https://images.unsplash.com/photo-1606811971618-4486d14f3f99?w=800&auto=format&fit=crop&q=60'),
('علاج العصب: متى يكون ضرورياً؟', 'لماذا نحتاج لسحب العصب وكيف يتم؟', 'يصبح علاج العصب ضرورياً عندما يصل التسوس أو العدوى إلى لب السن (العصب). العملية تتضمن إزالة العصب الملتهب، تنظيف القنوات، وحشوها لمنع العدوى المستقبلية.', 'د. نور الدين', '2025-10-08', 'علاج جذور', 'https://images.unsplash.com/photo-1609840114035-3c981b782dfe?w=800&auto=format&fit=crop&q=60'),
('حساسية الأسنان: الأسباب والعلاج', 'لماذا تشعر بألم عند شرب الماء البارد؟', 'حساسية الأسنان تحدث عند انكشاف طبقة العاج بسبب تآكل المينا أو انحسار اللثة. يمكن علاجها باستخدام معاجين مخصصة للحساسية أو إجراءات وقائية في العيادة.', NULL, NULL, 'عناية يومية', 'https://images.unsplash.com/photo-1542608503-b1ca99768296?w=800&auto=format&fit=crop&q=60'),
('تأثير التدخين على صحة الفم', 'مخاطر التدخين على الأسنان واللثة', 'التدخين يسبب تلون الأسنان، رائحة الفم الكريهة، ويزيد بشكل كبير من خطر الإصابة بأمراض اللثة وسرطان الفم. الإقلاع عن التدخين يحسن صحة الفم بشكل ملحوظ.', NULL, NULL, 'عناية يومية', 'https://images.unsplash.com/photo-1527137342181-19aab11a8670?w=800&auto=format&fit=crop&q=60'),
('رائحة الفم الكريهة: أسباب وحلول', 'كيف تتخلص من رائحة الفم المزعجة؟', 'أغلب حالات رائحة الفم سببها بكتيريا اللسان وبقايا الطعام. التنظيف الجيد، شرب الماء، وعلاج التسوس يساعد في التخلص منها. أحياناً يكون السبب مشاكل في المعدة.', NULL, NULL, 'تناظيف', 'https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=800&auto=format&fit=crop&q=60'),
('أضراس العقل: خلع أم بقاء؟', 'متى يجب خلع ضرس العقل؟', 'ليس كل ضرس عقل يحتاج لخلع. يتم الخلع إذا كان مدفوناً، يسبب ألماً، يضغط على الأسنان المجاورة، أو يصعب تنظيفه مما يسبب تسوساً متكرراً.', NULL, NULL, 'جراحة', 'https://images.unsplash.com/photo-1571772996211-2f02c972762a?w=800&auto=format&fit=crop&q=60'),
('السكري وصحة الأسنان', 'العلاقة بين مرض السكري وأمراض اللثة', 'مرضى السكري أكثر عرضة لالتهابات اللثة، والتهابات اللثة قد تجعل ضبط السكر أصعب. العناية الفائقة والمتابعة الدورية ضرورية لمرضى السكري.', NULL, NULL, 'عناية يومية', 'https://images.unsplash.com/photo-1505751172107-172120005701?w=800&auto=format&fit=crop&q=60'),
('الحمل وصحة الفم', 'نصائح للمرأة الحامل للعناية بأسنانها', 'التغيرات الهرمونية أثناء الحمل تزيد خطر التهاب اللثة (لثة الحمل). تنظيف الأسنان وتنظيف الجير آمن وضروري أثناء الحمل للحفاظ على صحة الأم والجنين.', NULL, NULL, 'تنظيف', 'https://images.unsplash.com/photo-1531983412531-1f49a365ffed?w=800&auto=format&fit=crop&q=60'),
('التغذية وصحة الأسنان', 'أطعمة تقوي الأسنان وأخرى تضرها', 'الكالسيوم وفيتامين د ضروريان لأسنان قوية. تجنب السكريات والنشويات اللزجة يقلل خطر التسوس. تناول الفواكه والخضروات المقرمشة يساعد في تنظيف الأسنان.', NULL, NULL, 'عناية يومية', 'https://images.unsplash.com/photo-1490818387583-1b9a2498d8d3?w=800&auto=format&fit=crop&q=60'),
('جسور الأسنان الثابتة', 'بديل تقليدي لتعويض الأسنان المفقودة', 'الجسر الثابت يعوض سناً مفقوداً بتثبيت سن صناعي على الأسنان المجاورة. خيار جيد لمن لا تناسبهم الزراعة، ولكنه يتطلب برد الأسنان السليمة المجاورة.', NULL, NULL, 'طقم الاسنان', 'https://images.unsplash.com/photo-1468494290481-1b0338787c80?w=800&auto=format&fit=crop&q=60'),
('تآكل الأسنان الحمضي', 'تأثير المشروبات الغازية والحمضيات', 'الأحماض في المشروبات الغازية والليمون تذيب طبقة المينا الصلبة، مما يؤدي لضعف الأسنان وحساسيتها. استخدم الماصة (الشفاطة) واغسل فمك بالماء بعد تناولها.', NULL, NULL, 'عناية يومية', 'https://images.unsplash.com/photo-1546173159-315724a93c9c?w=800&auto=format&fit=crop&q=60'),
('صرير الأسنان (الكجز)', 'مخاطر الضغط على الأسنان أثناء النوم', 'صرير الأسنان غالباً ما يكون بسبب التوتر. يسبب تآكل الأسنان، صداع، وآلام في الفك. الحل غالباً يكون بارتداء واقي ليلي (Night Guard) لحماية الأسنان.', NULL, NULL, 'جراحة', 'https://images.unsplash.com/photo-1512438248451-aa3150534c0e?w=800&auto=format&fit=crop&q=60'),
('تركيبات الزيركون', 'الجمال والمتانة في تركيبات الأسنان', 'الزيركون مادة قوية جداً ولونها مقارب للأسنان الطبيعية. تستخدم في التيجان والجسور وتعتبر خياراً ممتازاً يجمع بين القوة والناحية التجميلية.', NULL, NULL, 'حشوات تجميلية', 'https://images.unsplash.com/photo-1629909613654-28e377c37b09?w=800&auto=format&fit=crop&q=60'),
('خيط الأسنان المائي', 'هل يغني عن الخيط التقليدي؟', 'خيط الأسنان المائي فعال جداً في تنظيف ما بين الأسنان، خاصة لأصحاب التقويم والتركيبات. يمكن استخدامه كبديل أو مكمل للخيط التقليدي لنتائج أفضل.', NULL, NULL, 'عناية يومية', 'https://images.unsplash.com/photo-1598256989800-fe5f95da9787?w=800&auto=format&fit=crop&q=60'),
('الخوف من طبيب الأسنان', 'كيف تتغلب على فوبيا علاج الأسنان؟', 'الخوف من طبيب الأسنان شائع. ناقش مخاوفك مع طبيبك، ابدأ بزيارات بسيطة، واستخدم تقنيات الاسترخاء. التخدير الحديث جعل العلاج غير مؤلم تقريباً.', NULL, NULL, 'عناية يومية', 'https://images.unsplash.com/photo-1588776814546-1ffcf47267a5?w=800&auto=format&fit=crop&q=60'),
('تجميل اللثة بالليزر', 'علاج الابتسامة اللثوية وتصبغات اللثة', 'يمكن استخدام الليزر لتوريد اللثة الداكنة أو قص اللثة الزائدة في الابتسامة اللثوية (Gummy Smile). الإجراء سريع، قليل الألم، ونتائجه فورية.', NULL, NULL, 'تجميل', 'https://images.unsplash.com/photo-1606811971618-4486d14f3f99?w=800&auto=format&fit=crop&q=60'),
('أضرار تبييض الأسنان المنزلي', 'تحذيرات من وصفات الفحم والليمون', 'فرك الأسنان بالفحم أو الليمون أو البيكربونات قد يزيل التصبغات مؤقتاً ولكنه يكشط طبقة المينا بشكل دائم، مما يضعف الأسنان ويجعلها أكثر عرضة للاصفرار لاحقاً.', NULL, NULL, 'تجميل', 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=800&auto=format&fit=crop&q=60'),
('العناية بتقويم الأسنان', 'كيف تنظف أسنانك أثناء وجود التقويم؟', 'يتطلب التقويم عناية خاصة. استخدم فرشاة التقويم، الخيط المائي، وفرشاة ما بين الأسنان يومياً لمنع تراكم البلاك حول الحاصرات وحدوث تسوس أو بقع بيضاء.', NULL, NULL, 'تقويم', 'https://images.unsplash.com/photo-1523359366921-4c142d4d0dae?w=800&auto=format&fit=crop&q=60'),
('أسباب جفاف الفم', 'لماذا يقل اللعاب وكيف نعالجه؟', 'جفاف الفم قد يكون بسبب أدوية معينة، التدخين، أو أمراض. قلة اللعاب تزيد خطر التسوس بشكل كبير. شرب الماء ومضغ علكة خالية من السكر يساعد في التحفيز.', NULL, NULL, 'تشخيص', 'https://images.unsplash.com/photo-1542608503-b1ca99768296?w=800&auto=format&fit=crop&q=60'),
('حشوات الفضة (الأملغم) مقابل البيضاء', 'أيهما أفضل لأسنانك ولماذا؟', 'الحشوات البيضاء (الكومبوزيت) تجميلية وتلتحم بالسن، بينما الفضية (الأملغم) أقوى ولكن شكلها غير مقبول وتحتوي زئبق. الاتجاه العالمي نحو الحشوات البيضاء.', NULL, NULL, 'حشوات', 'https://images.unsplash.com/photo-1609840114035-3c981b782dfe?w=800&auto=format&fit=crop&q=60'),
('سرطان الفم: الكشف المبكر', 'علامات يجب الانتباه لها في الفم', 'قرحة لا تلتئم لأكثر من أسبوعين، بقع بيضاء أو حمراء غريبة، أو صعوبة في البلع. الفحص الدوري عند طبيب الأسنان يشمل فحص أنسجة الفم للكشف المبكر.', NULL, NULL, 'وقاية', 'https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?w=800&auto=format&fit=crop&q=60'),
('تقويم الأسنان الشفاف (Invisalign)', 'مميزات وعيوب التقويم غير المرئي', 'التقويم الشفاف مريح، غير مرئي، وقابل للإزالة. مثالي للكبار. لكنه يتطلب التزاماً بارتدائه 22 ساعة يومياً وقد لا يناسب جميع الحالات المعقدة.', NULL, NULL, 'تقويم', 'https://images.unsplash.com/photo-1588776814546-1ffcf47267a5?w=800&auto=format&fit=crop&q=60'),
('أضرار مص الإصبع للأطفال', 'تأثير العادات السيئة على نمو الفك', 'مص الإبهام لفترات طويلة قد يؤدي إلى بروز الأسنان الأمامية وتشوه في عظم الفك العلوي (العضة المفتوحة). يجب مساعدة الطفل على ترك العادة قبل سن الخامسة.', NULL, NULL, 'اطفال', 'https://images.unsplash.com/photo-1460380411175-d261998544d1?w=800&auto=format&fit=crop&q=60'),
('أنواع تركيبات الأسنان', 'الفرق بين التيجان والجسور والزراعة', 'التاج يغطي سناً واحداً، الجسر يعوض سناً مفقوداً بالاستناد على الجوار، والزراعة تعوض السن من الجذر. الطبيب يحدد الأنسب حسب حالة العظم والأسنان المجاورة.', NULL, NULL, 'طقم الاسنان', 'https://images.unsplash.com/photo-1629909613654-28e377c37b09?w=800&auto=format&fit=crop&q=60');
